  }, {x, y});

  // Blacksmith at cx=592, cy=0 (bug), use cx=592 with estimated center Y=384
  await click(592, 384);
  await page.waitForTimeout(2000);

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });

  const info = await page.evaluate(() => {
    const gs = window.__latestGameState;
    // Look for NPC dialogue in DOM
    const dialogEls = ['#notification', '.notification-text', '#notification-text', '.notification-description', 
                       '#dialog-text', '.dialog-text', '[id*="dialog"]', '[class*="dialog-text"]'];
    let dialogText = null;
    for (const sel of dialogEls) {
      const el = document.querySelector(sel);
      if (el && el.textContent.trim()) { dialogText = el.textContent.trim().substring(0,300); break; }
    }
    return JSON.stringify({
      pos: gs.player_position,
      hp: gs.player_stats.hp,
      dialogText
    });
  });
  return info;
}

